window.__QUIZ_DATA__=[{"id":"theory>Accounts>2003>1>a","subject":"Accounts","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"SUBSIDIARY BOOKS : MEANING AND IMPORTANCE","question":"What are books of prime entry?","images":[],"marking_scheme":"Book of prime entry: This is otherwise known as book of original entry or subsidiary books. It is the book in which transactions are first recorded as they occur before they are posted into the ledgers.","marks":"7.5","difficulty":"1"},{"id":"theory>Accounts>2003>1>b","subject":"Accounts","year":"2003","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"SUBSIDIARY BOOKS : MEANING AND IMPORTANCE","question":"List any four books of prime entry?","images":[],"marking_scheme":"- Sales daybook  - Purchase daybook  - Sales returns daybook  - Purchase returns daybook  - General Journal  - Cashbook","marks":"5","difficulty":"1"},{"id":"theory>Accounts>2003>1>c","subject":"Accounts","year":"2003","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"THE JOURNAL : MEANING AND USES OF JOURNAL","question":"State four uses of the General Journal.","images":[],"marking_scheme":"- For recording of asset sold on credit.  - For recording of asset bought on credit.  - For correction of errors.  - For recording of opening balances in ledger.  - For recording of closing balances in ledger.  - For making inter-ledger transfer.  - For recording of purchase or sales of assets.  - For writing off bad debts.  - For recording of adjustments of entries.","marks":"7.5","difficulty":"1"},{"id":"theory>Accounts>2003>2>a","subject":"Accounts","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ISSUES OF SHARES : MEANING AND CLASSES OF SHARES","question":"What is a share premium?","images":[],"marking_scheme":"When shares are issued at a price more than their nominal value. It is the difference between the issuing price and the nominal value.  Share premium is a capital reserve which is not available for distribution to shareholders. Separate account is opened for share premium.","marks":"15","difficulty":"2"},{"id":"theory>Accounts>2003>2>b","subject":"Accounts","year":"2003","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ISSUES OF SHARES : MEANING AND CLASSES OF SHARES","question":"List three purposes for which a share premium is utilized.","images":[],"marking_scheme":"- It is uses for providing for premium on Redemption of redeemable preference shares or debenture.  - It is use to write off preliminary expenses.  - It is use for issuing fully paid bonus shares.  - It is use for writing off issuing expenses, commission paid or discount allowed on shares.","marks":"5","difficulty":"2"},{"id":"theory>Accounts>2003>3","subject":"Accounts","year":"2003","type":"Theory","sub_label":"3","group":"CLOSENESS","topic":"SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES","question":"State four steps of converting incomplete records and single entry accounts to double entry accounts.","images":[],"marking_scheme":"- Draw up a statement of affairs at the beginning to determine opening capital.  - Draw up cash and bank account.  - Prepare creditors and debtors control account to determine purchases and sales for the year.  - Prepare expenses accounts to determine the amount chargeable for the year and ascertain drawings.  - Prepare final account i.e trading, profit & loss and balance sheet.","marks":"20","difficulty":"3"},{"id":"theory>Accounts>2003>4>a","subject":"Accounts","year":"2003","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"FINANCIAL SYSTEM : BENEFITS","question":"State four advantages that an accounting system can derive from the application of the computer.","images":[],"marking_scheme":"- Increases job satisfaction and effective use of time of operation.  - It is accurate.  - It is an automatic preparation of books of prime entry.  - It can be used to produce exception reports.  - It improve decision making process.  - It reduces labour and cost of labour.  - It reduces the monotony of producing lengthy and boring report with large amount of figures.","marks":"10","difficulty":"2"},{"id":"theory>Accounts>2003>4>b","subject":"Accounts","year":"2003","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"FINANCIAL SYSTEM : MEANING, FUNCTIONS AND FEATURES","question":"List two outputs of the accounting information system.","images":[],"marking_scheme":"- Profit & loss reports/accounts or statement report.  - Statement of financial position/balance sheet.  - Cashflow statements.  - Management Information reports.  - The payrolls.  - Stock records/stock valuation.","marks":"10","difficulty":"2"},{"id":"theory>Accounts>2003>5","subject":"Accounts","year":"2003","type":"Theory","sub_label":"5","group":"","topic":"PUBLIC SECTOR ACCOUNTING : ESTIMATES","question":"The following balances have been extracted from the books of Durodoluwa Local Government for the year ended 31st December, 2001.  Head\u20a6-  4001  4002  4003  4004  3001  3002  4005  3003  3004  4006  4007  4008  3005General revenue balance (1/1/2001)  Postages and stationery  Maintenance of vehicles  Purchase of drugs  Personnel costs  Subvention from Federal Government  Subvention from State Government  Grant to schools  Rates and fines  Licence renewal fees  Disposal of refuse  Salaries of traditional chiefs  Provision of street lights   Sale of grounded vehicles2,407,000  123,450  365,845  606,435  4,366,155  7,000,000  2,500,000  1,500,000  300,100  176,400  203,440  105,000  850,000  74,500  You are required to prepare a statement of revenue and expenditure for the local government for the year ended 31st December, 2001.","images":[],"marking_scheme":"**Durodoluwas Local Government  Revenue and expenditure statement for the year 31/12/2001  HeadRevenueAmount (\u20a6)3001  3002  3002  3003  3004  3005Revenue b/f  Subvention-federal govt.  Subvention-state govt.  Rates and fines  Licence renewals  Sales of Grounded Vehicles2,407,000  7,000,000  2,500,000  300,000  176,400  74,500Total revenue12,458,000    Less Expenditure  4001  4002  4003  4004  4005  4006  4007  4008Postages & Stationery  Maintenance of Vehicles  Purchase of drugs  Personnel cost  Subvention to schools  Disposal of refuse  Salaries of traditional chiefs  Street lights123,450  365,845  606,435  4,366,155  1,500,000  203,440  105,000  850,000              8,120,325Excess of revenue over expenditure4,337,675","marks":"20","difficulty":"3"},{"id":"theory>Accounts>2003>6>a","subject":"Accounts","year":"2003","type":"Theory","sub_label":"a","group":"","topic":"SINGLE ENTRY AND INCOMPLETE RECORDS : PREPARATION OF FINAL ACCOUNTS FROM INCOMPLETE RECORDS","question":"Mr. Ekpeyong is a petty trader dealing in electronic gadgets. He has not been keeping his books of accounts but has been taking notes of his transactions. The following information is made available for the year ended 31st December, 2001.    Sales   Cash banked  Cheques issued to creditors   Cash purchases  Wages and salaries paid by cash  Rent paid by cash  Transportation paid by cash  Telephone charges paid by cash\u20a6  200,000  130,000  105,000  30,000  4,000  2,000  5,400  800    The assets and liabilities at the beginning and end of the period are estimated as follows:      Stock  Bank balance  Cash balance  Trade debtors  Trade creditors1/1/2001  \u20a6  20,000  10,000  2,000  7,000  13,50031/12/2001  \u20a6  40,000  20,000  12,000  10,000  27,000","images":[],"marking_scheme":"MR. EKPEYONG  **Opening Statement of affairs as at 1/1/2001    Stock  Bank balance  Cash balance  Trade debtors\u20a6  20,000  10,000  2,000  7,000  less: creditors39,000  13,500Opening capital25,500","marks":"5","difficulty":"3"},{"id":"theory>Accounts>2003>6>b>i","subject":"Accounts","year":"2003","type":"Theory","sub_label":"i","group":"","topic":"SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS","question":"All differences in the reconciliation of takings, banking, disbursements and balances in hand at bank are to be regarded as Mr. Ekpeyong's personal drawings.  You are required to prepare    Opening Statement of Affairs as at 1st January, 2001","images":[],"marking_scheme":"Workings  Dr &nbsp &nbsp Creditors Control A/C &nbsp Cr  Cheque Issued  Bal. c/d105,000  27,000Bal. b/f  Credit purchases13,500  118,500132,000132,000bal. b/d27,000  Total purchases = 118,500 + 30,000  \u21d2 \u20a6148,500    Dr &nbsp &nbsp Debtors Control A/C &nbsp Cr    Bal. b/f  Credit sales\u20a6  7,000  3,000  Bal. c/d  \u20a6  10,000  Bal. b/d10,000   Total sales = 3,000 + 200,000  \u21d2 \u20a6203,000","marks":"5","difficulty":"3"},{"id":"theory>Accounts>2003>6>b>ii","subject":"Accounts","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT","question":"All differences in the reconciliation of takings, banking, disbursements and balances in hand at bank are to be regarded as Mr. Ekpeyong's personal drawings.  You are required to prepare  Trading, Profit and Loss Account for the year ended 31st December 2001.","images":[],"marking_scheme":"Dr &nbsp &nbsp &nbsp Trading, Profit or loss account for the year ended 31/12/2001&nbsp &nbsp &nbsp Cr    Opening Stock  Purchases\u20a6  20,000  148,500  Sales\u20a6  203,000  closing stock168,500  40,000      Cost of sales  Gross profit c/d128,500  74,500      203,000 203,000Wages & Salaries  Rent  Transport  Telephone  Net profit4,000  2,000  5,400  800  62,300Gross profit b/d           74,500           74,50074,500","marks":"5","difficulty":"3"},{"id":"theory>Accounts>2003>6>b>iii","subject":"Accounts","year":"2003","type":"Theory","sub_label":"iii","group":"","topic":"THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET","question":"All differences in the reconciliation of takings, banking, disbursements and balances in hand at bank are to be regarded as Mr. Ekpeyong's personal drawings.  You are required to prepare  Balance Sheet as at that date.","images":[],"marking_scheme":"Balance sheet as at 31st Decemer, 2001    Capital  Add: Net profit    Less: Drawings    Creditors\u20a6  25,500   62,300   87,800   32,800   55,000  27,000  Stock  Debtors  Cash at bank  Cash in hand      \u20a6  40,000  10,000  20,000  12,000      82,00082,000    To determine drawings, we prepare two-columns cash book.    DetailsCashBankDetailsCashBankbal. b/f  Sales  Cash \u2284                  \u20a6  2,000  200,000                    \u20a6  10,000    130,000                    Bank \u2284  Creditors  Purchases  Wages & Salaries  Rent  Transport  Telephone  Drawings (balancing figure)  balance c/d\u20a6  130,000    30,000  4,000  2,000  5,400  800  17,800  12,000\u20a6    105,000            15,000  20,000202,000140,000202,000140,000Balance b/d12,00020,000    Total drawings = 17,800 + 15,000  \u21d2 32,800","marks":"5","difficulty":"3"},{"id":"theory>Accounts>2003>7>a","subject":"Accounts","year":"2003","type":"Theory","sub_label":"a","group":"","topic":"BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT","question":"James was examining his bank statement for the month of December, 2001. He discovered that the balance on the statement disagreed with the Cash Book balance which was \u20a618,440. On investigation in the following were revealed:  (a) The opening balance in the Cash Book for the month had been wrongly brought down as \u20a63,705 instead of \u20a63,750.  (b) Two cheques for \u20a616,300 and \u20a64,650 which were issued to creditors had not been presented for payment.  (c) The bank returned a cheque for \u20a63,800 deposited on 5th December.  (d) A cheque for \u20a67,600 deposited on 24th December was not credited until 2nd January, 2002.  (e) Cost of cheque book and other charges by bank totalling \u20a6385 was yet to be entered in the Cash Book.  (f) The bank had paid \u20a6850 on standing order to Premier Insurance Company  You are required to prepare:    Adjusted Cash Book","images":[],"marking_scheme":"Adjusted Cash Book    balance b/f  Suspense (error in opening-balance)      \u20a6  18,440  45        dishonoured cheques  Bank charges  Standing order  Balance c/d\u20a6  3800  385  850  13,45018,48518,485Balance b/d13,450","marks":"10","difficulty":"2"},{"id":"theory>Accounts>2003>7>b","subject":"Accounts","year":"2003","type":"Theory","sub_label":"b","group":"","topic":"BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT","question":"James was examining his bank statement for the month of December, 2001. He discovered that the balance on the statement disagreed with the Cash Book balance which was \u20a618,440. On investigation in the following were revealed:  (a) The opening balance in the Cash Book for the month had been wrongly brought down as \u20a63,705 instead of \u20a63,750.  (b) Two cheques for \u20a616,300 and \u20a64,650 which were issued to creditors had not been presented for payment.  (c) The bank returned a cheque for \u20a63,800 deposited on 5th December.  (d) A cheque for \u20a67,600 deposited on 24th December was not credited until 2nd January, 2002.  (e) Cost of cheque book and other charges by bank totalling \u20a6385 was yet to be entered in the Cash Book.  (f) The bank had paid \u20a6850 on standing order to Premier Insurance Company  You are required to prepare:  Bank Reconciliation Statement for December, 2001.","images":[],"marking_scheme":"Bank Reconciliation Statement    Bal. as per adjusted cashbook  Add: Unpresented cheques (16,300 + 4,650)  Less uncredited cheques\u20a6    20,950  7,600\u20a6  13,450    13,350Balance as per Bank Statement26,800","marks":"10","difficulty":"2"},{"id":"theory>Accounts>2003>8>a","subject":"Accounts","year":"2003","type":"Theory","sub_label":"a","group":"","topic":"ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS","question":"The following is a summary of the Cash Book of Agubiko Country Club:    Balance 1/4/2001  Members subscriptions  Entrance fees  Bar takings  Competition receipts  Sundry receipts          \u20a6  23,700  178,600  16,000  284,000  38,200  400            Staff wages  Bar supplies  Rent for 18 months to 30/6/2002  Rates  Secretary's salary  Electricity and telephone   Compettion prizes  Deposit with Onyi Community Bank  Balance - 31/3/2002\u20a6  66,900  252,000  36,000  14,000  15,600  68,500  18,500  40,000  29,400540,900540,900    Additional information:  (a) The assets of the club as at 1st April, 2001, were:  Furniture and equipment  Bar stocks  Prizes at hand  Owing for bar supplies\u20a6240,000  \u20a613,000  \u20a64,000  \u20a626,000    (b) The assets of the club as at 31st March, 2002, were:  Bar stocks  Prizes  Owing for bar supplies\u20a615,000  \u20a62,500  \u20a628,000    (c) Subscriptions outstanding as at 31st March, 2002, totalled \u20a65,000. Subscriptions received during the year under review included \u20a63,500 in respect of the previous year and \u20a62,000 in respect of the year beginning 1st April, 2002.    (d) Interest on the deposit with Onyi Community Bank for the year 31st March, 2002, amounting to \u20a62,400 had not been received.    (e) Provide for depreciation on furniture and equipment at 10%.     You are required to prepare:    Statement showing the Accumulated Fund as at 1st April, 2001.","images":[],"marking_scheme":"Statement of accumulated fund as at 1/4/2001    Furniture and equipment  Bar stock  Prizes   Cash  Debtors for subscription\u20a6           \u20a6  240,000  13,000  4,000  23,700  3,500  less: creditors  Accrued Rent  26,000  6,000284,200    32,000Accumulated Fund252,200","marks":"7.5","difficulty":"3"},{"id":"theory>Accounts>2003>8>b","subject":"Accounts","year":"2003","type":"Theory","sub_label":"b","group":"","topic":"ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS","question":"The following is a summary of the Cash Book of Agubiko Country Club:    Balance 1/4/2001  Members subscriptions  Entrance fees  Bar takings  Competition receipts  Sundry receipts          \u20a6  23,700  178,600  16,000  284,000  38,200  400            Staff wages  Bar supplies  Rent for 18 months to 30/6/2002  Rates  Secretary's salary  Electricity and telephone   Compettion prizes  Deposit with Onyi Community Bank  Balance - 31/3/2002\u20a6  66,900  252,000  36,000  14,000  15,600  68,500  18,500  40,000  29,400540,900540,900    Additional information:  (a) The assets of the club as at 1st April, 2001, were:  Furniture and equipment  Bar stocks  Prizes at hand  Owing for bar supplies\u20a6240,000  \u20a613,000  \u20a64,000  \u20a626,000    (b) The assets of the club as at 31st March, 2002, were:  Bar stocks  Prizes  Owing for bar supplies\u20a615,000  \u20a62,500  \u20a628,000    (c) Subscriptions outstanding as at 31st March, 2002, totalled \u20a65,000. Subscriptions received during the year under review included \u20a63,500 in respect of the previous year and \u20a62,000 in respect of the year beginning 1st April, 2002.    (d) Interest on the deposit with Onyi Community Bank for the year 31st March, 2002, amounting to \u20a62,400 had not been received.    (e) Provide for depreciation on furniture and equipment at 10%.     You are required to prepare:  Income and Expenditure Account for the year ended 31st March, 2002.","images":[],"marking_scheme":"Income and expenditure account for the year ended 31/3/2002    Wages  Rent (12 months)  Rates  Secretary's salary  Electricity & Telephone  Competition prizes (18,500 + 4,000 + 2,500)  depreciation  Excess of income over exp.\u20a6  66,000  24,000  14,000  15,600  68,500  20,000  24,000  34,100  Entrance fees  Subscriptions  Profit from bar trading  Competition receipts  Sundry receipts   Interest on deposit      \u20a6  16,000  178,100  32,000  38,200  400  2,400      267,100267,100","marks":"7.5","difficulty":"3"},{"id":"theory>Accounts>2003>8>c","subject":"Accounts","year":"2003","type":"Theory","sub_label":"c","group":"","topic":"ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS","question":"The following is a summary of the Cash Book of Agubiko Country Club:    Balance 1/4/2001  Members subscriptions  Entrance fees  Bar takings  Competition receipts  Sundry receipts          \u20a6  23,700  178,600  16,000  284,000  38,200  400            Staff wages  Bar supplies  Rent for 18 months to 30/6/2002  Rates  Secretary's salary  Electricity and telephone   Compettion prizes  Deposit with Onyi Community Bank  Balance - 31/3/2002\u20a6  66,900  252,000  36,000  14,000  15,600  68,500  18,500  40,000  29,400540,900540,900    Additional information:  (a) The assets of the club as at 1st April, 2001, were:  Furniture and equipment  Bar stocks  Prizes at hand  Owing for bar supplies\u20a6240,000  \u20a613,000  \u20a64,000  \u20a626,000    (b) The assets of the club as at 31st March, 2002, were:  Bar stocks  Prizes  Owing for bar supplies\u20a615,000  \u20a62,500  \u20a628,000    (c) Subscriptions outstanding as at 31st March, 2002, totalled \u20a65,000. Subscriptions received during the year under review included \u20a63,500 in respect of the previous year and \u20a62,000 in respect of the year beginning 1st April, 2002.    (d) Interest on the deposit with Onyi Community Bank for the year 31st March, 2002, amounting to \u20a62,400 had not been received.    (e) Provide for depreciation on furniture and equipment at 10%.     You are required to prepare:  Balance Sheet as at that date.","images":[],"marking_scheme":"\u20a6\u20a6Assets\u20a6Accumulated Fund  Add excess of Income    less:  Creditors (28,000 - 26,000)  Subscription in advance  Interest paid252,000  34,100      2,000  2,000  2,400  286,300          (6,400)  Furniture (WK 1)  Bar Stock  Prizes  Cash  Sub in arrears   Rent prepaid    216,000  15,000  2,500  29,400  5,000  12,000    279,900279,900    WORKING NOTES    Furniture \u00d7 equipment = 10%  10100\u00d7240,000=24,000  NE.V = 240,000-24,000=216,000","marks":"5","difficulty":"3"},{"id":"theory>Accounts>2003>9>a","subject":"Accounts","year":"2003","type":"Theory","sub_label":"a","group":"","topic":"REVALUATION ACCOUNT : ENTRIES IN THE BOOKS OF ACCOUNT","question":"Idowu has been in business for several years as a sole-proprietor of a hotel business. The balance sheet of his business on 31st December, 2001, was as follows:    Capital  Profit\u20a6  200,000  26,000  Leasehold premises  Fixtures and Fittings\u20a6  100,000  120,000  Drawings    Creditors  Accruals226,000  12,000  214,000  47,000  13,000  Current Assets:  Stock &nbsp &nbsp &nbsp 38,000  Debtors &nbsp &nbsp &nbsp 7,000  Bank &nbsp &nbsp &nbsp 9,000220,000        54,000274,000274,000    On 1st January 2002, he decided to admit Alaba into the business to form a partnership on the following items:  (a) Alaba is to contribute \u20a6250,000 as capital   (b) Profits and losses are to be shared equally.  (c) The partnership is to take over the assets and liabilities at their book values except for those revalued as follows:  Leasehold premises  Fixtures and Fittings   Stock\u20a6150,000  \u20a6100,000  \u20a635,000    (d) Idowu is to maintain a capital of \u20a6250,000 by credit from revaluation or private resources. Any balance shall be kept in his current account.    You are required to prepare:    Revaluation Account.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"7.5","difficulty":"3"},{"id":"theory>Accounts>2003>9>b","subject":"Accounts","year":"2003","type":"Theory","sub_label":"b","group":"","topic":"PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR","question":"Idowu has been in business for several years as a sole-proprietor of a hotel business. The balance sheet of his business on 31st December, 2001, was as follows:    Capital  Profit\u20a6  200,000  26,000  Leasehold premises  Fixtures and Fittings\u20a6  100,000  120,000  Drawings    Creditors  Accruals226,000  12,000  214,000  47,000  13,000  Current Assets:  Stock &nbsp &nbsp &nbsp 38,000  Debtors &nbsp &nbsp &nbsp 7,000  Bank &nbsp &nbsp &nbsp 9,000220,000        54,000274,000274,000    On 1st January 2002, he decided to admit Alaba into the business to form a partnership on the following items:  (a) Alaba is to contribute \u20a6250,000 as capital   (b) Profits and losses are to be shared equally.  (c) The partnership is to take over the assets and liabilities at their book values except for those revalued as follows:  Leasehold premises  Fixtures and Fittings   Stock\u20a6150,000  \u20a6100,000  \u20a635,000    (d) Idowu is to maintain a capital of \u20a6250,000 by credit from revaluation or private resources. Any balance shall be kept in his current account.    You are required to prepare:  Partners' Capital Account","images":["data:image/png;base64,"],"marking_scheme":"","marks":"7.5","difficulty":"3"},{"id":"theory>Accounts>2003>9>c","subject":"Accounts","year":"2003","type":"Theory","sub_label":"c","group":"","topic":"GOODWILL ACCOUNTS : TREATMENT OF GOODWILL ON ADMISSION OF PARTNERS AND CHANGES IN RATIO","question":"Idowu has been in business for several years as a sole-proprietor of a hotel business. The balance sheet of his business on 31st December, 2001, was as follows:    Capital  Profit\u20a6  200,000  26,000  Leasehold premises  Fixtures and Fittings\u20a6  100,000  120,000  Drawings    Creditors  Accruals226,000  12,000  214,000  47,000  13,000  Current Assets:  Stock &nbsp &nbsp &nbsp 38,000  Debtors &nbsp &nbsp &nbsp 7,000  Bank &nbsp &nbsp &nbsp 9,000220,000        54,000274,000274,000    On 1st January 2002, he decided to admit Alaba into the business to form a partnership on the following items:  (a) Alaba is to contribute \u20a6250,000 as capital   (b) Profits and losses are to be shared equally.  (c) The partnership is to take over the assets and liabilities at their book values except for those revalued as follows:  Leasehold premises  Fixtures and Fittings   Stock\u20a6150,000  \u20a6100,000  \u20a635,000    (d) Idowu is to maintain a capital of \u20a6250,000 by credit from revaluation or private resources. Any balance shall be kept in his current account.    You are required to prepare:  Opening Balance Sheet for the partnership on 1st January, 2002.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"}];